CREATE TABLE users (id TEXT PRIMARY KEY, name TEXT NOT NULL, email TEXT UNIQUE NOT NULL, avatar_url TEXT, role TEXT NOT NULL DEFAULT 'user', token TEXT, created_at TEXT NOT NULL DEFAULT (datetime ('now')));
CREATE TABLE feature_requests (id TEXT PRIMARY KEY, title TEXT NOT NULL CHECK (length (title) <= 120), description TEXT NOT NULL CHECK (length (description) <= 2000), status TEXT NOT NULL DEFAULT 'open' CHECK (status IN ('open', 'under-review', 'planned', 'in-progress', 'done', 'declined')), vote_count INTEGER NOT NULL DEFAULT 0, user_id TEXT NOT NULL REFERENCES users (id), created_at TEXT NOT NULL DEFAULT (datetime ('now')), updated_at TEXT NOT NULL DEFAULT (datetime ('now')));
CREATE TABLE votes (id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users (id), feature_request_id TEXT NOT NULL REFERENCES feature_requests (id), created_at TEXT NOT NULL DEFAULT (datetime ('now')), UNIQUE (user_id, feature_request_id));
